import os,re,json
files=[]
for dp,_,fs in os.walk('.'):
    if '/.git' in dp: continue
    for f in fs:
        if f.endswith('.java'): files.append(os.path.join(dp,f)[2:])
texts={p:open(p,encoding='utf-8').read() for p in files}
def strip_comments(s):
    def repl(m): return ' '*(m.end()-m.start())
    s=re.sub(r'/\\*.*?\\*/', repl, s, flags=re.S)
    s=re.sub(r'//.*', lambda m:' '*(m.end()-m.start()), s)
    return s
stripped={p:strip_comments(t) for p,t in texts.items()}
class_head=re.compile(r'\\bclass\\s+(\\w+)\\b(?P<mid>["'^{};]*)'"\\{', re.S)
# find class blocks and parents
classes_by_file={}; parents={}
for path,s in stripped.items():
    cls=[]
    for m in class_head.finditer(s):
        name=m.group(1); mid=m.group('mid')
        em=re.search(r'\\bextends\\s+([\\w.]+)', mid)
        parent=(em.group(1).split('.')[-1] if em else '')
        b=m.end()-1; depth=0; end=len(s)-1
        for i,ch in enumerate(s[b:], b):
            if ch=='{': depth+=1
            elif ch=='}':
                depth-=1
                if depth==0: end=i; break
        cls.append((m.start(),end,name,parent))
        if parent: parents[name]=parent
    classes_by_file[path]=cls
sub={'JsonDeserializer'}; changed=True
while changed:
    changed=False
    for c,p in parents.items():
        if p in sub and c not in sub:
            sub.add(c); changed=True
# print missing check
# method declarations named deserialize 2 args in subclasses
method_decl=re.compile(r'(?:(?:@\\w+(?:\\(["'^)]*'"\\))?\\s*)*(?:public|protected|private|static|final|abstract|synchronized)\\s+)+[\\w."'$<>'"\\[\\]? ,]+?\\s+deserialize\\s*\\(\\s*(?:final\\s+)?JsonParser\\s+\\w+\\s*,\\s*(?:final\\s+)?DeserializationContext\\s+\\w+\\s*\\)', re.S)
# all method contexts for call sites
any_method=re.compile(r'(?:(?:@\\w+(?:\\(["'^)]*'"\\))?\\s*)*(?:public|protected|private|static|final|abstract|synchronized)\\s+)+[\\w."'$<>'"\\[\\]? ,]+?\\s+(\\w+)\\s*\\(["'^;{}]*'"\\)\\s*(?:throws ["'^{]+)?'"\\{', re.S)
def method_contexts(path):
    s=stripped[path]; out=[]
    for m in any_method.finditer(s):
        b=s.find('{', m.end()-1)
        if b<0: continue
        depth=0; end=len(s)-1
        for i,ch in enumerate(s[b:], b):
            if ch=='{': depth+=1
            elif ch=='}':
                depth-=1
                if depth==0: end=i; break
        pos=m.start(); enc=[c for c in classes_by_file[path] if c[0]<=pos<=c[1]]
        cls=enc[-1][2] if enc else ''
        out.append((m.start(),end,cls,m.group(1)))
    return out
methods_by_file={p:method_contexts(p) for p in files}
def enclosing_class(path,pos):
    enc=[c for c in classes_by_file[path] if c[0]<=pos<=c[1]]
    return enc[-1][2] if enc else ''
def enclosing_method(path,pos):
    enc=[m for m in methods_by_file[path] if m[0]<=pos<=m[1]]
    if not enc: return None
    m=enc[-1]; return (m[2]+'.' if m[2] else '')+m[3]
# detect anonymous symbol with line maybe
sites=set(); decls=[]
for path,s in stripped.items():
    for m in method_decl.finditer(s):
        pos=m.start(); cls=enclosing_class(path,pos)
        if path=='src/main/java/com/fasterxml/jackson/databind/JsonDeserializer.java' or cls in sub:
            sites.add(f'{path}:{cls}.deserialize' if cls else f'{path}:deserialize')
            decls.append((path,cls,pos))
        else:
            pre=s[max(0,pos-800):pos]
            news=re.findall(r'new\\s+([\\w.]+)', pre)
            if news and news[-1].split('.')[-1] in sub:
                line=s[:pos].count('\\n')+1
                sites.add(f'{path}:anonymous@{line}.deserialize')
# Build typed names per file (global crude)
type_name_pat=re.compile(r'\\b([A-Z]\\w*(?:<["'^;=(){}]+>)?)'"\\s+([A-Za-z_]\\w*)\\b')
subtype_names=set(sub)|{'JsonDeserializer'}
# call parser simple: find .deserialize( and unqualified/super.deserialize, count top-level args until )
def call_args_end(s, openpos):
    depth=0; args=1; i=openpos+1
    while i<len(s):
        ch=s[i]
        if ch=='(': depth+=1
        elif ch==')':
            if depth==0: return args,i
            depth-=1
        elif ch==',' and depth==0: args+=1
        i+=1
    return None,None
for path,s in stripped.items():
    # names typed as JsonDeserializer/subclasses anywhere in file (locals/fields/params)
    typed=set()
    for tm in type_name_pat.finditer(s):
        typ=tm.group(1).split('<',1)[0]
        if typ in subtype_names:
            typed.add(tm.group(2))
    # include common fields explicitly declared across line with generics
    for tm in re.finditer(r'\\bJsonDeserializer\\s*<["'^;]+?>'"\\s+([A-Za-z_]\\w*)', s): typed.add(tm.group(1))
    for m in re.finditer(r'(?:(\\b(?:super|this|[A-Za-z_]\\w*)\\b|\\))\\s*\\.\\s*)?deserialize\\s*\\(', s):
        name=m.group(1); openpos=m.end()-1; argc,end=call_args_end(s,openpos)
        if argc"'!=2: continue
        pos=m.start(); meth=enclosing_method(path,pos)
        if not meth: continue
        cls=enclosing_class(path,pos)
        affected=False
        # skip declaration itself by seeing previous char context? call regex may match decl? It has no dot and is followed by (, argc 2; ignore if line before has public/protected/return type
        line_start=s.rfind('"'\\n',0,pos)+1; prefix=s[line_start:pos]
        if re.search(r'\\b(public|protected|private|abstract)\\b', prefix):
            continue
        if name in ('super','this'):
            affected = (cls in sub)
        elif name is None:
            affected = (cls in sub)
        elif name in typed:
            affected=True
        # expression receiver ) e.g getValueDeserializer().deserialize or find...Deserializer().deserialize: inspect previous 120 chars
        pre=s[max(0,pos-160):pos]
        if not affected and ('.getValueDeserializer()' in pre or 'findRootValueDeserializer' in pre or 'findContextualValueDeserializer' in pre or 'findNonContextualValueDeserializer' in pre):
            affected=True
        if affected:
            sites.add(f'{path}:{meth}')
print('SITES',len(sites))
for x in sorted(sites): print(x)
